#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Create a SQL warehouse
 *
 * This example demonstrates:
 * - Creating a SQL warehouse
 * - Waiting for the warehouse to reach RUNNING state
 * - Getting warehouse connection details
 * - Stopping and deleting the warehouse
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 * - Appropriate permissions to create SQL warehouses
 *
 * Usage:
 *   npx ts-node examples/workspace/sql/create-warehouse.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const warehouseName = `sdk-warehouse-${Date.now()}`;

    console.log(`Creating SQL warehouse: ${warehouseName}`);

    try {
        // Create SQL warehouse
        const warehouse = await client.warehouses.create({
            name: warehouseName,
            cluster_size: "2X-Small",
            max_num_clusters: 1,
            auto_stop_mins: 10,
            enable_photon: true,
        });

        console.log(`✓ Warehouse creation initiated`);
        console.log(`  Warehouse ID: ${warehouse.id}`);

        // Wait for warehouse to be ready
        console.log(`\nWaiting for warehouse to be ready...`);

        const waiter = await client.warehouses.get({
            id: warehouse.id!,
        });

        // Poll until warehouse is running
        let isReady = false;
        let attempts = 0;
        const maxAttempts = 30; // 5 minutes max

        while (!isReady && attempts < maxAttempts) {
            const status = await client.warehouses.get({
                id: warehouse.id!,
            });

            console.log(`  State: ${status.state}`);

            if (status.state === "RUNNING") {
                isReady = true;
                console.log(`\n✓ Warehouse is ready!`);
            } else if (
                status.state === "STOPPED" ||
                status.state === "DELETED"
            ) {
                console.log(
                    `\n✗ Warehouse reached unexpected state: ${status.state}`
                );
                break;
            }

            if (!isReady) {
                await new Promise((resolve) => setTimeout(resolve, 10000)); // Wait 10 seconds
                attempts++;
            }
        }

        // Get final warehouse details
        const finalWarehouse = await client.warehouses.get({
            id: warehouse.id!,
        });

        console.log(`\nWarehouse Details:`);
        console.log(`  ID: ${finalWarehouse.id}`);
        console.log(`  Name: ${finalWarehouse.name}`);
        console.log(`  Cluster Size: ${finalWarehouse.cluster_size}`);
        console.log(`  State: ${finalWarehouse.state}`);
        console.log(`  JDBC URL: ${finalWarehouse.jdbc_url || "N/A"}`);
        console.log(
            `  ODBC Params: ${finalWarehouse.odbc_params?.hostname || "N/A"}`
        );

        // Stop the warehouse
        console.log(`\nStopping warehouse...`);
        await client.warehouses.stop({
            id: warehouse.id!,
        });

        // Wait for warehouse to stop
        await new Promise((resolve) => setTimeout(resolve, 5000));

        console.log(`✓ Warehouse stopped`);

        // Cleanup: Delete the warehouse
        console.log(`\nCleaning up: deleting warehouse ${warehouse.id}`);
        await client.warehouses.delete({
            id: warehouse.id!,
        });
        console.log(`✓ Warehouse deleted`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
